import { ChatContainer, type PublicConfig } from '@carbon/ai-chat';
import { createRoot } from 'react-dom/client';
import { customSendMessage } from './customSendMessage';

const config: PublicConfig = {
  messaging: { customSendMessage },
};

function App() {
  return <ChatContainer {...config} />;
}

createRoot(document.querySelector('#root')!).render(<App />);

import { ChatInstance, CustomSendMessageOptions, MessageRequest, MessageResponseTypes } from '@carbon/ai-chat';

export async function customSendMessage(
  request: MessageRequest,
  options: CustomSendMessageOptions,
  instance: ChatInstance,
) {
  const userText = request.input.text ?? '';
  const reply = await callYourBackend(userText, { signal: options.signal });
  instance.messaging.addMessage({
    output: {
      generic: [{ response_type: MessageResponseTypes.TEXT, text: reply }],
    },
  });
}

const responseId = 'r1';
let acc = '';
for await (const piece of yourTokenStream(userText, { signal: options.signal })) {
  acc += piece;
  await instance.messaging.addMessageChunk({
    streaming_metadata: { response_id: responseId },
    partial_item: {
      response_type: MessageResponseTypes.TEXT,
      text: acc,
      streaming_metadata: { id: 'item-1' },
    },
  });
}
await instance.messaging.addMessageChunk({
  final_response: { id: responseId, output: { generic: [{ response_type: MessageResponseTypes.TEXT, text: acc }] } },
});

instance.messaging.addMessage({
  output: {
    generic: [
      { response_type: MessageResponseTypes.TEXT, text: 'Pick one:' },
      {
        response_type: MessageResponseTypes.OPTION,
        title: 'Options',
        options: [
          { label: 'Plans', value: { input: { text: 'show plans' } } },
          { label: 'Pricing', value: { input: { text: 'show pricing' } } },
        ],
      },
    ],
  },
});

function renderUserDefinedResponse(state, _instance) {
  const item = state.messageItem;
  if (item?.user_defined?.kind === 'weather') {
    return <WeatherCard data={item.user_defined.data} />;
  }
  return null;
}

<ChatContainer {...config} renderUserDefinedResponse={renderUserDefinedResponse} />;
