const config: PublicConfig = { messaging: { customSendMessage } };

function App() { return <ChatContainer {...config} />; }
createRoot(document.querySelector('#root')!).render(<App />);

import { ChatInstance, CustomSendMessageOptions, MessageRequest, MessageResponseTypes } from '@carbon/ai-chat';

export async function customSendMessage(request: MessageRequest, options: CustomSendMessageOptions, instance: ChatInstance) {
  const responseId = crypto.randomUUID();
  let acc = '';
  for await (const token of streamFromBackend(request.input.text ?? '', { signal: options.signal })) {
    acc += token;
    await instance.messaging.addMessageChunk({
      streaming_metadata: { response_id: responseId },
      partial_item: { response_type: MessageResponseTypes.TEXT, text: acc, streaming_metadata: { id: 'item-1' } },
    });
  }
  await instance.messaging.addMessageChunk({
    final_response: { id: responseId, output: { generic: [{ response_type: MessageResponseTypes.TEXT, text: acc }] } },
  });
}

import { ChatContainer, type PublicConfig, MessageResponseTypes } from '@carbon/ai-chat';

